import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as n,c as a,d as s}from"./app-0a44add1.js";const e="/img/study/html/seo.jpg",l="/img/study/html/seo1.jpg",c="/img/study/html/seo2.jpg",p={},i=s('<h2 id="语义化" tabindex="-1"><a class="header-anchor" href="#语义化" aria-hidden="true">#</a> 语义化</h2><h3 id="理解" tabindex="-1"><a class="header-anchor" href="#理解" aria-hidden="true">#</a> 理解</h3><p>Web语义化是指使用恰当语义的html标签、class类名等内容，让页面具有良好的结构与含义，从而让人和机器都能快速理解网页内容。语义化的web页面一方面可以让机器在更少的人类干预情况下收集并研究网页的信息，从而可以读懂网页的内容，然后将收集汇总的信息进行分析，结果为人类所用；另一方面它可以让开发人员读懂结构和用户以及屏幕阅读器（如果访客有视障）能够读懂内容。 简单来说就是利于 SEO，便于阅读维护理解。</p><figure><img src="'+e+`" alt=" " tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="优点" tabindex="-1"><a class="header-anchor" href="#优点" aria-hidden="true">#</a> 优点</h3><ul><li>有利于开发者的维护和理解；</li><li>有利于机器对文档内容进行正确的解读；</li><li>有利于搜索引擎爬虫正确的读取内容，优化SEO；</li><li>有利于即使样式表丢失，网页仍能维持基本的内容供给用户阅读；</li></ul><h3 id="html语义化" tabindex="-1"><a class="header-anchor" href="#html语义化" aria-hidden="true">#</a> html语义化</h3><p>HTML为网页文档内容提供上下文结构和含义。对于HTML体系而言，Web语义化是指使用语义恰当的标签，使页面有良好的结构，让页面元素有含义，便于被浏览器、搜索引擎解析、利于SEO。通常我们所说的HTML应该是完全脱离表现信息的，其中的标签应该都是语义化地定义了文档的结构。 代码示例：</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>html</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>body</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>article</span><span class="token punctuation">&gt;</span></span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>header</span><span class="token punctuation">&gt;</span></span>
                <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h1</span><span class="token punctuation">&gt;</span></span>h1 - WEB 语义化<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h1</span><span class="token punctuation">&gt;</span></span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>header</span><span class="token punctuation">&gt;</span></span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>nav</span><span class="token punctuation">&gt;</span></span>
                <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>ul</span><span class="token punctuation">&gt;</span></span>
                    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>li</span><span class="token punctuation">&gt;</span></span>nav1 - HTML语义化<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>li</span><span class="token punctuation">&gt;</span></span>
                    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>li</span><span class="token punctuation">&gt;</span></span>nav2 - CSS语义化<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>li</span><span class="token punctuation">&gt;</span></span>
                <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>ul</span><span class="token punctuation">&gt;</span></span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>nav</span><span class="token punctuation">&gt;</span></span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>section</span><span class="token punctuation">&gt;</span></span>
                section1 - HTML语义化
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>section</span><span class="token punctuation">&gt;</span></span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>section</span><span class="token punctuation">&gt;</span></span>
                section2 - CSS语义化
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>section</span><span class="token punctuation">&gt;</span></span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>time</span> <span class="token attr-name">datetime</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>2018-03-23<span class="token punctuation">&quot;</span></span> <span class="token attr-name">pubdate</span><span class="token punctuation">&gt;</span></span>time - 2018年03月23日<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>time</span><span class="token punctuation">&gt;</span></span>
            <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>footer</span><span class="token punctuation">&gt;</span></span> footer - by 小维<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>footer</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>article</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>body</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>html</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th style="text-align:left;">标签</th><th style="text-align:center;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>&lt;article&gt;</code></td><td style="text-align:center;">定义文章。</td></tr><tr><td style="text-align:left;"><code>&lt;aside&gt;</code></td><td style="text-align:center;">定义页面内容以外的内容。</td></tr><tr><td style="text-align:left;"><code>&lt;details&gt;</code></td><td style="text-align:center;">定义用户能够查看或隐藏的额外细节。</td></tr><tr><td style="text-align:left;"><code>&lt;figcaption&gt;</code></td><td style="text-align:center;">定义<code>&lt;figure&gt;</code>元素的标题。</td></tr><tr><td style="text-align:left;"><code>&lt;figure&gt;</code></td><td style="text-align:center;">规定自包含内容，比如图示、图表、照片、代码清单等。</td></tr><tr><td style="text-align:left;"><code>&lt;footer&gt;</code></td><td style="text-align:center;">定义文档或节的页脚。</td></tr><tr><td style="text-align:left;"><code>&lt;header&gt;</code></td><td style="text-align:center;">规定文档或节的页眉。</td></tr><tr><td style="text-align:left;"><code>&lt;main&gt;</code></td><td style="text-align:center;">规定文档的主内容。</td></tr><tr><td style="text-align:left;"><code>&lt;mark&gt;</code></td><td style="text-align:center;">定义重要的或强调的文本。</td></tr><tr><td style="text-align:left;"><code>&lt;nav&gt;</code></td><td style="text-align:center;">定义导航链接。</td></tr><tr><td style="text-align:left;"><code>&lt;section&gt;</code></td><td style="text-align:center;">定义文档中的节。</td></tr><tr><td style="text-align:left;"><code>&lt;summary&gt;</code></td><td style="text-align:center;">定义 <code>&lt;details&gt;</code> 元素的可见标题。</td></tr><tr><td style="text-align:left;"><code>&lt;time&gt;</code></td><td style="text-align:center;">定义日期/时间。</td></tr></tbody></table><h3 id="css语义化" tabindex="-1"><a class="header-anchor" href="#css语义化" aria-hidden="true">#</a> CSS语义化</h3><p>CSS语义就是class和ID命名的语义。class属性作为HTML与CSS衔接的纽带，其本意是用来描述元素内容的。指用易于理解的名称对html标签附加的class或id命名。如果说HTML语义化标签是给机器看的，那么CSS命名的语义化就是给人看的。良好的CSS命名方式减少沟通调试成本，易于理解。</p><h2 id="seo" tabindex="-1"><a class="header-anchor" href="#seo" aria-hidden="true">#</a> SEO</h2><p>SEO（Search Engine Optimization），搜索引擎优化。百度百科对其的解释是一种方式：利用搜索引擎的规则提高网站在有关搜索引擎内的自然排名。目的是让其在行业内占据领先地位，获得品牌收益。很大程度上是网站经营者的一种商业行为，将自己或自己公司的排名前移。</p><p>搜索引擎是怎么工作的呢？主要分为以下三个步骤：</p><ol><li>爬行抓取，网络爬虫通过特定规则跟踪网页的链接，从一个链接爬到另一个链接，把爬行的数据存入本地数据库</li><li>使用索引器对数据库中重要信息进行处理，如标题、关键字、摘要，或者进行全文索引，在索引数据库中，网页文字内容，关键词出现的位置、字体、颜色、加粗、斜体等相关信息都有相应记录。</li><li>索引器将用户提交的搜索词与数据中的信息进行匹配，从索引数据库中找出所有包含搜索词的网页，并且根据排名算法计算出哪些网页应该排在前面，然后按照一定格式返回给用户</li></ol><p><img src="`+l+'" alt=" " loading="lazy"><br><img src="'+c+'" alt=" " loading="lazy"></p><p>从图中，可以看到，爬虫的爬取首先选取一部分精心挑选的种子URL，将这些URL放入待抓取URL队列，从待抓取URL队列中取出待抓取在URL，解析DNS，并且得到主机的ip，并将URL对应的网页下载下来，存储进已下载网页库中。此外，将这些URL放进已抓取URL队列。分析已抓取URL队列中的URL，分析其中的其他URL，并且将URL放入待抓取URL队列，从而进入下一个循环。这就需要让我们考虑，怎样才能让爬虫更多的爬取到我们的网站。</p><h3 id="权重" tabindex="-1"><a class="header-anchor" href="#权重" aria-hidden="true">#</a> 权重</h3><table><thead><tr><th style="text-align:left;">网页内容</th><th style="text-align:center;">权重分数</th></tr></thead><tbody><tr><td style="text-align:left;">内部链接文字</td><td style="text-align:center;">10</td></tr><tr><td style="text-align:left;">标题title</td><td style="text-align:center;">10</td></tr><tr><td style="text-align:left;">域名</td><td style="text-align:center;">7</td></tr><tr><td style="text-align:left;">H1，H2字号标题</td><td style="text-align:center;">5</td></tr><tr><td style="text-align:left;">路径或文件名</td><td style="text-align:center;">4</td></tr><tr><td style="text-align:left;">title属性：（不是<code>&lt;title&gt;</code>，是A标签中title属性）</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:left;">加粗或斜体</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:left;">alt标记</td><td style="text-align:center;">0.5</td></tr></tbody></table><h3 id="优化" tabindex="-1"><a class="header-anchor" href="#优化" aria-hidden="true">#</a> 优化</h3><ul><li>突出重要内容---合理的设计title、description和keywords</li><li>语义化书写HTML代码，符合W3C标准</li><li>图片img标签添加alt和title属性</li><li>链接<code>&lt;a&gt;</code>页内标签添加title属性</li><li>使用h1标签自带权重</li></ul>',22),o=[i];function d(r,u){return n(),a("div",null,o)}const h=t(p,[["render",d],["__file","语义化与SEO.html.vue"]]);export{h as default};
